---@class LMapEffectPlayer
local LMapEffectPlayer = LxClass("LMapEffectPlayer", nil)
-----------------------------------------------------------------
local LxTimer = LXFW.LxTimer
local LDisplayEffect = LDisplayEffect
-----------------------------------------------------------------

function LMapEffectPlayer:LMapEffectPlayer()
	self._effectKeyList = {}  --key=key,value=effect
	self._effectTimeList = {}

	self._chengRoot = nil
	self._effectRootList = nil

	self._chengneiEffDataList = nil
	self._effDataList = nil
end

-----------------------------------------------------------------
function LMapEffectPlayer:Init(chengRoot, effectRoot, chengneiEffDataList, effDataList)
	self._chengneiEffDataList = chengneiEffDataList
	self._effDataList = effDataList


	self._chengRoot = chengRoot
	self._effectRootList =  effectRoot

	self._effLen = effDataList and #effDataList or 0
end
------------------------------------------------------------------

-----------------------------------------------------------------
function LMapEffectPlayer:DestroyMapEffectAll()
	local effectKeyList = self._effectKeyList
	if effectKeyList then
		for k,v in pairs(effectKeyList) do
			v:Destroy()
		end
		--print("DestroyMapEffectAll")
		self._effectKeyList = nil
	end
end

function LMapEffectPlayer:DestroyMapEffectByKey(key)
	local effectKeyList = self._effectKeyList
	if not effectKeyList then return end

	if effectKeyList[key] then
		print("DestroyMapEffectByKey key = ",key)
		effectKeyList[key]:Destroy()
		effectKeyList[key] = nil
	end
end

function LMapEffectPlayer:CreateMapEffect(trans, effName, effKey)
	if not trans then
		print("trans is nil")
		return
	end
	
	local key = effKey or trans.gameObject.name
	local effectKeyList = self._effectKeyList
	if not effectKeyList then
		effectKeyList = {}
		self._effectKeyList = effectKeyList
	end

	if effectKeyList[key] then
		local dpTrans = effectKeyList[key]:GetDisplayTrans()
		if CS.IsValidObject(dpTrans)  then
			-- false 到 true 重新播特效
			dpTrans.gameObject:SetActive(false)
			dpTrans.gameObject:SetActive(true)
			return
		end
	end

	local dpEff = LDisplayEffect:New()
	effectKeyList[key] = dpEff
	dpEff:CreateEffect(trans, effName)
	dpEff:SetLoadedFunction(function()
		local dpTrans = dpEff:GetDisplayTrans()
		dpTrans.localPosition = Vector3.zero
		dpTrans.localScale = Vector3(1,1,1)
		dpTrans.name = effName
	end)
	dpEff:StartLoadEffect()
end

-----------------------------------------------------------------
function LMapEffectPlayer:ResetEffect()
	local effectList = self._effDataList or {}
	local effectRooList = self._effectRootList or {}
	for i = 1,#effectList do
		local effTrans = effectRooList[i]
		if effTrans then
			CS.ShowObject(effTrans, false)
			local effectData = effectList[i]
			self:CreateMapEffect(effTrans,effectData.name,effectData.name)
		end
	end

	local chengneiEffDataList = self._chengneiEffDataList or {}
	local chengneiRoot = self._chengRoot
	if chengneiRoot then
		for i = 1,#chengneiEffDataList do
			local effectData = chengneiEffDataList[i]
			self:CreateMapEffect(chengneiRoot,effectData.name,effectData.name)
		end
	end

	self:StartPlayEffect()
end

function LMapEffectPlayer:StartPlayEffect()
	local palyEffectTransNum = math.random(1,4)
	local randomTransT = self:GetRandomTab(1, self._effLen, palyEffectTransNum)
	local effectRootList = self._effectRootList
	local effectList = self._effDataList

	local maxTimes
	for i,transIndex in pairs(randomTransT) do
		local trans = effectRootList[transIndex]
		if trans then
			local showTimes = math.random(3,10)
			local effectData = effectList[transIndex]
			local time = effectData.time or 1
			local payTime = showTimes * time
			local timeKey = "key" .. transIndex
			if not maxTimes then
				maxTimes = payTime
			else
				if payTime > maxTimes then
					maxTimes = payTime
				end
			end
			self:CreateEffectTimer(timeKey,time,showTimes,trans)
		end
	end
	---第3步然后当他们各自随到的播放次数都播完了，进入一个cd为30s的冷却
	maxTimes = maxTimes or 0
	self:StartDelayTimer(maxTimes + 30)
end

function LMapEffectPlayer:CreateEffectTimer(key,time,showTimes,effTrans)
	local effectTimeList = self._effectTimeList
	local timer = effectTimeList[key]
	local num = showTimes
	local func = function()
		CS.ShowObject(effTrans,false)
		if num < 1 then
			self:ClearTimer(key)
			return
		end
		num = num - 1
		CS.ShowObject(effTrans,true)
	end

	if timer then
		timer:Reset(func, time, -1, false)
	else
		timer = LxTimer.LoopTimeCall(func,time,false,-1)
		effectTimeList[key] = timer
	end
end

function LMapEffectPlayer:ClearAllTimer()
	local effectTimeList = self._effectTimeList
	if effectTimeList then
		for k,v in pairs(effectTimeList) do
			LxTimer.LoopTimeStop(v)
		end
		self._effectTimeList = {}
	end
end

function LMapEffectPlayer:ClearTimer(timerKey)
	if timerKey then
		local timer = self._effectTimeList[timerKey]
		if timer then 
			LxTimer.LoopTimeStop(timer)
		end
		self._effectTimeList[timerKey] = nil
	end
end

function LMapEffectPlayer:FillNum(m,n)
	local j,k
	if n then
		j,k = m,n
	else
		j,k = 1,m
	end
	local t = {}
	for i = j,k do 
		table.insert(t,i) 
	end
	return t
end

function LMapEffectPlayer:GetRandomTab(m,n,cnt)
	local tmp = self:FillNum(m,n)
	if cnt > n - m + 1 then
		return tmp
	end
	local x = 0
	local t = {}
	math.randomseed(os.time())
	while cnt > 0 do
		x = math.random(1,n - m + 1)
		table.insert(t,tmp[x])
		table.remove(tmp,x)
		cnt = cnt - 1
		m = m + 1
	end
	return t
end

function LMapEffectPlayer:StartDelayTimer(time)
	self:StopDelayTimer()
	self._mapDelayTimer = LxTimer.DelayTimeCall(function ()
		self:ClearAllTimer()
		self:StartPlayEffect()
	end,time, false)
	--printErrorN("光效切换倒计时开始 .."..tostring(time).."s")
end

function LMapEffectPlayer:StopDelayTimer()
	if self._mapDelayTimer then
		LxTimer.DelayTimeStop(self._mapDelayTimer)
		self._mapDelayTimer = nil
	end
end

------------------------------------------------------------------
function LMapEffectPlayer:RestartPlay()
	if self._bDestroy then return end
	if self._bPlaying then return end

	self._bPlaying = true
	self:ResetEffect()
end

function LMapEffectPlayer:StopPlay()
	self._bPlaying = false

	self:DestroyMapEffectAll()
	self:StopDelayTimer()
	self:ClearAllTimer()
end

function LMapEffectPlayer:Destroy()
	self:StopPlay()
	table.remove(self)
	self._bDestroy = true
end

return LMapEffectPlayer